import React, { useState } from 'react';

const CartPopup = ({ product, onAddToCart }) => {
  const [size, setSize] = useState('');
  const [color, setColor] = useState('');

  const handleAddToCart = () => {
    onAddToCart({ ...product, size, color });
  };

  return (
    <div className="fixed top-0 left-0 w-full h-full bg-gray-800 bg-opacity-50 flex items-center justify-center">
      <div className="bg-white p-6 rounded-lg shadow-lg">
        <h2 className="text-lg font-bold mb-4">{product.name}</h2>
        <div className="mb-4">
          <label htmlFor="size" className="block font-medium mb-2">Size:</label>
          <select
            id="size"
            value={size}
            onChange={(e) => setSize(e.target.value)}
            className="border border-gray-300 rounded-md px-4 py-2 w-full"
          >
            <option value="">Select size</option>
            <option value="S">Small</option>
            <option value="M">Medium</option>
            <option value="L">Large</option>
          </select>
        </div>
        <div className="mb-4">
          <label htmlFor="color" className="block font-medium mb-2">Color:</label>
          <select
            id="color"
            value={color}
            onChange={(e) => setColor(e.target.value)}
            className="border border-gray-300 rounded-md px-4 py-2 w-full"
          >
            <option value="">Select color</option>
            <option value="red">Red</option>
            <option value="blue">Blue</option>
            <option value="green">Green</option>
          </select>
        </div>
        <button
          onClick={handleAddToCart}
          className="bg-amber-400 text-white px-4 py-2 rounded-md hover:bg-amber-500 transition-colors"
        >
          Add to Cart
        </button>
      </div>
    </div>
  );
};

export default CartPopup;
